**@CircuitBreaker annotation pattern:**

```java
import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import org.springframework.stereotype.Service;

@Service
public class PaymentNotificationService {
    private final NotificationClient notificationClient;
    private final NotificationQueue queue;

    PaymentNotificationService(NotificationClient nc, NotificationQueue q) {
        notificationClient = nc; queue = q;
    }

    // The annotation wraps this method with a circuit breaker proxy:
    @CircuitBreaker(
        name = "notification",         // matches application.yml instance name
        fallbackMethod = "notificationFallback"  // called when circuit is OPEN or exception
    )
    public void sendPaymentConfirmation(String paymentId, String phone) {
        // Called only when circuit is CLOSED or HALF-OPEN:
        notificationClient.sendSMS(
            phone, "Your payment " + paymentId + " was successful.");
    }

    // Fallback: SAME return type, SAME parameters + Exception as last param
    private void notificationFallback(
            String paymentId, String phone, Exception e) {
        // This runs when:
        //   1. Circuit is OPEN (fast fail — no real call made)
        //   2. The real method threw an exception (failure recorded + fallback called)
        log.warn("Notification fallback for payment {} — reason: {}",
            paymentId, e.getMessage());
        queue.enqueue(paymentId, phone);  // retry later
    }

    // For methods with return values:
    @CircuitBreaker(name = "product-service", fallbackMethod = "emptyProductFallback")
    public List<Product> getProducts(String category) {
        return productClient.getByCategory(category);  // HTTP call
    }

    private List<Product> emptyProductFallback(String category, Exception e) {
        log.warn("Product service unavailable for category {}", category);
        return List.of();  // return empty list — page still renders
    }
}
```

