```java
@Service
@Slf4j
public class RestaurantAvailabilityService {
    private final RestaurantClient client;

    @CircuitBreaker(
        name = "restaurant-availability",
        fallbackMethod = "defaultAvailability"
    )
    public RestaurantStatus checkAvailability(String restaurantId) {
        return client.getStatus(restaurantId);  // HTTP call to external service
    }

    private RestaurantStatus defaultAvailability(
            String restaurantId, Exception e) {
        log.warn("Restaurant availability service down for {}: {}",
            restaurantId, e.getMessage());
        // Optimistic fallback: show restaurant, verify later
        return RestaurantStatus.ASSUME_AVAILABLE;
    }
}
```

